new_hidden_tests.call:
try:
    deblur_system_call(['--min-size', '50'], 'nonexistent.fasta')
    assert False, 'Expected FileNotFoundError'
except FileNotFoundError as e:
    assert 'nonexistent.fasta' in str(e)

try:
    deblur_system_call(['--seqs-fp', 'other.fasta'], 'test.fasta')
    assert False, 'Expected ValueError'
except ValueError as e:
    assert '--seqs-fp' in str(e)

try:
    deblur_system_call(['--is-worker-thread=true'], 'test.fasta')
    assert False, 'Expected ValueError'
except ValueError as e:
    assert '--is-worker-thread' in str(e)
